"use client";

import { useEffect, useState } from "react";

export default function Dashboard() {
  const [reports, setReports] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchReports();
  }, []);

  const fetchReports = async () => {
    try {
      const res = await fetch("/api/report");
      const data = await res.json();
      setReports(data.data || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const verifyReport = async (id: string, status: string) => {
    try {
      const res = await fetch("/api/verify", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ id, status }),
      });

      const data = await res.json();

      if (data.success) {
        alert(`Report ${status}`);
        fetchReports();
      } else {
        alert(data.message);
      }
    } catch (err) {
      console.error(err);
    }
  };

  const pending = reports.filter(
    (r) => r.status === "under_verification"
  );

  return (
    <div className="p-10">
      <h1 className="text-2xl font-bold mb-6">
        🛠 Admin Verification Panel
      </h1>

      {loading ? (
        <p>Loading...</p>
      ) : pending.length === 0 ? (
        <p>No reports pending verification 🎉</p>
      ) : (
        <div className="space-y-6">
          {pending.map((report) => (
            <div
              key={report.id}
              className="bg-white p-5 rounded shadow border"
            >
              <h2 className="text-blue-700 font-bold">
                {report.case_id}
              </h2>

              <p className="font-medium">{report.title}</p>
              <p className="text-sm text-gray-600">
                {report.description}
              </p>

              <p className="text-sm text-gray-500">
                📍 {report.location}
              </p>

              {report.image_url && (
                <img
                  src={report.image_url}
                  className="mt-3 w-full max-h-64 object-cover rounded"
                />
              )}

              <div className="mt-4">
                <button
                  onClick={() =>
                    verifyReport(report.id, "verified")
                  }
                  className="bg-green-600 text-white px-4 py-2 rounded mr-2"
                >
                  ✅ Approve
                </button>

                <button
                  onClick={() =>
                    verifyReport(report.id, "rejected")
                  }
                  className="bg-red-600 text-white px-4 py-2 rounded"
                >
                  ❌ Reject
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}